@push('scripts')
<script>
(()=>{const csrf=document.querySelector('meta[name=csrf-token]').content,base=`{{route('disaster.payouts.centers.families',$center)}}`,releaseBase=`{{url('/disaster/payouts/releases')}}`;let page=1,timer,current,photoBlob,stream;const modal=new bootstrap.Modal('#payoutModal'),$=s=>document.querySelector(s),esc=v=>String(v??'—').replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c])),badge=(v,t)=>`<span class="badge badge-light-${t}">${esc(v)}</span>`;
async function request(url,options={}){options.headers={Accept:'application/json','X-CSRF-TOKEN':csrf,...options.headers};const r=await fetch(url,options),j=await r.json().catch(()=>({}));if(!r.ok)throw new Error(j.message||Object.values(j.errors||{}).flat().join('\n')||'The request could not be completed.');return j}
function query(){const p=new URLSearchParams({page,per_page:15,search:$('#search').value,workflow_status:$('#workflow-filter').value,payout_status:$('#payout-filter').value,housing_condition:$('#housing-filter').value,house_ownership:$('#ownership-filter').value,disaster_id:$('#disaster-filter').value,assigned_from:$('#assigned-from').value,assigned_to:$('#assigned-to').value,sort:$('#sort').value,direction:$('#sort').value==='assigned_at'?'desc':'asc'});return `${base}?${p}`}
async function loadFamilies(){const body=$('#family-rows');body.innerHTML='<tr><td colspan="10" class="text-center py-12"><span class="spinner-border text-primary"></span><div class="text-muted mt-3">Loading assigned families...</div></td></tr>';$('#table-error').classList.add('d-none');try{const j=await request(query());body.innerHTML=j.data.length?j.data.map((f,i)=>`<tr><td>${(j.meta.from||1)+i}</td><td><strong>${esc(f.dafac_reference)}</strong><div class="text-muted fs-7">${esc(f.tciss_reference)}</div></td><td class="fw-semibold">${esc(f.household_head)}<div class="text-muted fs-7 mw-250px text-truncate">${esc(f.address)}</div></td><td>${esc(f.barangay)}</td><td>${f.family_members} additional<div class="text-muted fs-7">${f.household_size} total</div></td><td>${esc(f.housing_condition)}<div class="text-muted fs-7">${esc(f.house_ownership)}</div></td><td>${badge(f.workflow_status,'primary')}</td><td>${badge(f.payout_status,f.payout_status==='Released'?'success':'warning')}<div class="mt-1">${badge(f.photo_status,f.photo_status==='Captured'?'success':'danger')}</div></td><td>${f.assigned_at?new Date(f.assigned_at).toLocaleDateString():'—'}</td><td><button class="btn btn-sm btn-primary open-family" data-url="${esc(f.open_url)}">Open</button></td></tr>`).join(''):'<tr><td colspan="10"><div class="text-center py-12"><i class="ki-duotone ki-people fs-3x text-muted"><span class="path1"></span><span class="path2"></span></i><h4 class="mt-4">No evacuated families are currently assigned to this evacuation center.</h4></div></td></tr>';body.querySelectorAll('.open-family').forEach(b=>b.onclick=()=>openFamily(b.dataset.url));renderPagination(j.meta)}catch(e){body.innerHTML='';$('#table-error').textContent=e.message;$('#table-error').classList.remove('d-none')}}
function renderPagination(m){$('#pagination').innerHTML=m.total?`<div class="text-muted">Showing ${m.from}–${m.to} of ${m.total}</div><div class="btn-group"><button class="btn btn-sm btn-light" id="prev" ${m.current_page<=1?'disabled':''}>Previous</button><button class="btn btn-sm btn-light" disabled>Page ${m.current_page} of ${m.last_page}</button><button class="btn btn-sm btn-light" id="next" ${m.current_page>=m.last_page?'disabled':''}>Next</button></div>`:'';$('#prev')?.addEventListener('click',()=>{page--;loadFamilies()});$('#next')?.addEventListener('click',()=>{page++;loadFamilies()})}
['#workflow-filter','#payout-filter','#housing-filter','#ownership-filter','#disaster-filter','#assigned-from','#assigned-to','#sort'].forEach(s=>$(s).onchange=()=>{page=1;loadFamilies()});$('#search').oninput=()=>{clearTimeout(timer);timer=setTimeout(()=>{page=1;loadFamilies()},350)};
async function openFamily(url){resetPhoto();modal.show();$('#modal-loading').classList.remove('d-none');$('#modal-content').classList.add('d-none');try{current=(await request(url)).data;const f=current.affected_family,p=current.payout,d=current.defaults;$('#modal-reference').textContent=`${current.dafac.reference||'No DAFAC'} / ${current.tciss.reference||'No TCISS'}`;$('#beneficiary-summary').innerHTML=`<div class="summary-grid">${Object.entries({'Household Head':f.household_head,'Birthdate / Age':`${f.birthdate||'—'} / ${f.age??'—'}`,'Address':f.address,'Barangay':f.barangay,'Evacuation Center':current.evacuation_center.name,'Family Members':f.family_members,'Household Size':f.household_size,'Housing':`${f.housing_condition} / ${f.house_ownership}`,'Workflow':f.workflow_status,'Payout Status':p?.status||'Not Scheduled'}).map(([k,v])=>`<div><div class="text-muted fs-7">${k}</div><div class="fw-semibold">${esc(v)}</div></div>`).join('')}</div>`;$('#member-rows').innerHTML=current.family_members.length?current.family_members.map(m=>`<tr><td>${esc(m.name)}</td><td>${esc(m.birthdate)} / ${esc(m.age)}</td><td>${esc(m.relationship)}</td><td>${esc(m.sex)}</td><td>${esc(m.occupation)}</td><td>${esc(m.health_condition)}</td><td>${esc(m.remarks_code)}</td></tr>`).join(''):'<tr><td colspan="7" class="text-center text-muted">No additional family members recorded.</td></tr>';const form=$('#release-form');form.assistance_kind.value=p?.assistance_kind||d.assistance_kind||'';form.quantity.value=p?.quantity||1;form.amount.value=p?.amount||d.amount||'';form.provider.value=p?.provider||d.provider||'';form.photo_caption.value=p?.notes||'';$('#payout-date').value=p?.payout_date||d.payout_date||'';$('#released-by').value=p?.released_by||'';$('#configuration-warning').classList.toggle('d-none',!!p);if(!p)$('#configuration-warning').textContent='No payout record is configured for this beneficiary.';$('#payout-history').innerHTML=current.payout_history.length?`<table class="table table-row-dashed"><thead><tr><th>Status</th><th>Assistance</th><th>Amount</th><th>Provider</th><th>Released</th><th>By</th></tr></thead><tbody>${current.payout_history.map(h=>`<tr><td>${badge(h.status,h.status==='Released'?'success':'warning')}</td><td>${esc(h.assistance_kind)}</td><td>${esc(h.amount)}</td><td>${esc(h.provider)}</td><td>${h.released_at?new Date(h.released_at).toLocaleString():'—'}</td><td>${esc(h.released_by)}</td></tr>`).join('')}</tbody></table>`:'<div class="text-muted">No payout history.</div>';if(p?.photo_url)$('#photo-preview').src=p.photo_url,$('#photo-preview').classList.remove('d-none');const locked=!p?.can_release;$('#release-button').disabled=locked;[...form.querySelectorAll('input:not([readonly])')].forEach(x=>x.disabled=locked);$('#start-camera').disabled=locked;$('#photo-input').disabled=locked;$('#release-button').textContent=p?.status==='Released'?'Already Released':'Mark as Released';$('#modal-loading').classList.add('d-none');$('#modal-content').classList.remove('d-none')}catch(e){$('#modal-loading').innerHTML=`<div class="alert alert-danger">${esc(e.message)}</div>`}}
function resetPhoto(){photoBlob=null;$('#photo-input').value='';$('#photo-preview').removeAttribute('src');$('#photo-preview').classList.add('d-none');$('#remove-photo').classList.add('d-none');$('#camera-error').textContent='';stream?.getTracks().forEach(t=>t.stop());$('#camera').classList.add('d-none');$('#capture-photo').classList.add('d-none')}
$('#photo-input').onchange=async e=>{const file=e.target.files[0];if(!file)return;if(!['image/jpeg','image/png','image/webp'].includes(file.type)||file.size>8*1024*1024){e.target.value='';return $('#camera-error').textContent='Use a JPEG, PNG, or WEBP image up to 8 MB.'}photoBlob=await compress(file);preview(photoBlob)};
async function compress(file){if(file.size<1500000)return file;const img=await createImageBitmap(file),scale=Math.min(1,1600/Math.max(img.width,img.height)),c=document.createElement('canvas');c.width=img.width*scale;c.height=img.height*scale;c.getContext('2d').drawImage(img,0,0,c.width,c.height);return new Promise(r=>c.toBlob(r,'image/jpeg',.82))}
function preview(blob){$('#photo-preview').src=URL.createObjectURL(blob);$('#photo-preview').classList.remove('d-none');$('#remove-photo').classList.remove('d-none')}
$('#start-camera').onclick=async()=>{try{stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment'}});$('#camera').srcObject=stream;$('#camera').classList.remove('d-none');$('#capture-photo').classList.remove('d-none')}catch(e){$('#camera-error').textContent='Camera access was denied or is unavailable. Upload an existing photo instead.'}};
$('#capture-photo').onclick=()=>{const v=$('#camera'),c=$('#snapshot'),max=1600,scale=Math.min(1,max/Math.max(v.videoWidth,v.videoHeight));c.width=v.videoWidth*scale;c.height=v.videoHeight*scale;c.getContext('2d').drawImage(v,0,0,c.width,c.height);c.toBlob(b=>{photoBlob=b;preview(b);stream?.getTracks().forEach(t=>t.stop());$('#camera').classList.add('d-none');$('#capture-photo').classList.add('d-none')},'image/jpeg',.82)};$('#remove-photo').onclick=resetPhoto;
$('#release-form').onsubmit=async e=>{e.preventDefault();if(!current?.payout?.id)return;if(!photoBlob&&!current.payout.has_photo)return Swal.fire({text:'A beneficiary payout photo is required.',icon:'error'});const confirm=await Swal.fire({text:'Mark this assistance as released? This action cannot be repeated.',icon:'question',showCancelButton:true,confirmButtonText:'Yes, release assistance'});if(!confirm.isConfirmed)return;const fd=new FormData(e.target);fd.set('idempotency_key',crypto.randomUUID());if(photoBlob)fd.set('photo',photoBlob,'beneficiary-payout.jpg');const button=$('#release-button');button.disabled=true;try{const j=await request(`${releaseBase}/${current.payout.id}/mark-released`,{method:'POST',body:fd});await Swal.fire({text:j.message,icon:'success'});modal.hide();loadFamilies()}catch(error){Swal.fire({text:error.message,icon:'error'});button.disabled=false}};
document.querySelector('#payoutModal').addEventListener('hidden.bs.modal',()=>stream?.getTracks().forEach(t=>t.stop()));loadFamilies()})();
</script>
@endpush
